--- src/scene/mesh/shared/MeshGeometry.ts
+++ src/scene/mesh/shared/MeshGeometry.ts
@@ -123,6 +123,18 @@
     constructor(...args: [MeshGeometryOptions] | [Float32Array, Float32Array, Uint32Array])
     {
         // ...
     }

+    /**
+     * Updates the geometry with new positions, uvs and indices.
+     * 
+     * @param {Float32Array} positions - The positions of the mesh.
+     * @param {Float32Array} uvs - The UVs of the mesh.
+     * @param {Uint32Array} indices - The indices of the mesh.
+     */
+    public updateGeometry(positions: Float32Array, uvs: Float32Array, indices: Uint32Array): void
+    {
+        this.attributes.aPosition.buffer.update(positions);
+        this.attributes.aUV.buffer.update(uvs);
+        this.indexBuffer.update(indices);
+    }
+
     get positions(): Float32Array
     {
         return this.attributes.aPosition.buffer.data as Float32Array;
@@ -151,6 +163,14 @@
         this.indexBuffer.data = value;
     }

+    /**
+     * Destroys the mesh geometry.
+     */
+    public destroy(): void
+    {
+        this.attributes.aPosition.buffer.destroy();
+        this.attributes.aUV.buffer.destroy();
+        this.indexBuffer.destroy();
+    }
 }
--- src/scene/mesh/Mesh.ts
+++ src/scene/mesh/Mesh.ts
@@ -123,6 +123,18 @@
     public set geometry(value: Geometry)
     {
         // ...
+        if (this.geometry !== value)
+        {
+            if (this._geometry)
+            {
+                this._geometry.destroy();
+            }
+            this._geometry = value;
+            // update the buffers
+            if (value instanceof MeshGeometry)
+            {
+                value.updateGeometry(value.positions, value.uvs, value.indices);
+            }
+        }
     }
